import{_ as s,o as e,c as n,a2 as t}from"./chunks/framework.BZO4qERu.js";const u=JSON.parse('{"title":"騎砍2 | 混合兵種進階戰術：不是人多就會贏","description":"","frontmatter":{},"headers":[],"relativePath":"bannerlord/advanced-tactics.md","filePath":"bannerlord/advanced-tactics.md"}'),l={name:"bannerlord/advanced-tactics.md"};function i(p,a,r,c,d,h){return e(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="騎砍2-混合兵種進階戰術-不是人多就會贏" tabindex="-1">騎砍2 | 混合兵種進階戰術：不是人多就會贏 <a class="header-anchor" href="#騎砍2-混合兵種進階戰術-不是人多就會贏" aria-label="Permalink to &quot;騎砍2 | 混合兵種進階戰術：不是人多就會贏&quot;">​</a></h1><hr><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>90% 的戰鬥輸掉，不是因為兵不夠多，是因為兵種搭配錯了。這篇把進階戰術思維講清楚——從陣型邏輯到針對性克制。</p><hr><h2 id="一、兵種三角克制" tabindex="-1">一、兵種三角克制 <a class="header-anchor" href="#一、兵種三角克制" aria-label="Permalink to &quot;一、兵種三角克制&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>        步兵（扛線/反騎）</span></span>
<span class="line"><span>         /          \\</span></span>
<span class="line"><span>        /            \\</span></span>
<span class="line"><span>  弓兵（遠程輸出）← 被騎兵剋 → 騎兵（衝鋒/機動）</span></span>
<span class="line"><span>        \\            /</span></span>
<span class="line"><span>         \\          /</span></span>
<span class="line"><span>          互相配合</span></span></code></pre></div><ul><li>騎兵衝鋒 → 剋弓兵（弓兵被近身就完了）</li><li>步兵盾牆 → 剋騎兵（騎兵衝不穿密集步兵）</li><li>弓兵遠程 → 剋步兵（步兵走過來先被射殘）</li></ul><hr><h2 id="二、陣型邏輯" tabindex="-1">二、陣型邏輯 <a class="header-anchor" href="#二、陣型邏輯" aria-label="Permalink to &quot;二、陣型邏輯&quot;">​</a></h2><h3 id="_2-1-層次布陣" tabindex="-1">2.1 層次布陣 <a class="header-anchor" href="#_2-1-層次布陣" aria-label="Permalink to &quot;2.1 層次布陣&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[敵方]</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>─── 弓兵（最後排，高地）───  ← 最安全，輸出最大化</span></span>
<span class="line"><span>─── 步兵（中排，盾牆）───     ← 保護弓兵，扛敵方衝鋒</span></span>
<span class="line"><span>─── 騎兵（兩翼）───           ← 機動打擊，繞背衝鋒</span></span></code></pre></div><h3 id="_2-2-為什麼要分層" tabindex="-1">2.2 為什麼要分層 <a class="header-anchor" href="#_2-2-為什麼要分層" aria-label="Permalink to &quot;2.2 為什麼要分層&quot;">​</a></h3><ul><li>弓兵在最後 → 不被敵方騎兵衝</li><li>步兵在中間 → 什麼都能扛</li><li>騎兵在兩翼 → 隨時出擊或保護側面</li></ul><hr><h2 id="三、針對性克制戰術" tabindex="-1">三、針對性克制戰術 <a class="header-anchor" href="#三、針對性克制戰術" aria-label="Permalink to &quot;三、針對性克制戰術&quot;">​</a></h2><h3 id="_3-1-敵方是騎兵主力-庫塞特-瓦蘭迪亞" tabindex="-1">3.1 敵方是騎兵主力（庫塞特/瓦蘭迪亞） <a class="header-anchor" href="#_3-1-敵方是騎兵主力-庫塞特-瓦蘭迪亞" aria-label="Permalink to &quot;3.1 敵方是騎兵主力（庫塞特/瓦蘭迪亞）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>對策：</span></span>
<span class="line"><span>- 步兵排方陣（F3+F3）扛騎兵衝鋒</span></span>
<span class="line"><span>- 弓兵射馬（馬倒了騎兵就是步兵）</span></span>
<span class="line"><span>- 地形選森林或橋樑</span></span>
<span class="line"><span>- 不要追他們（你追不上）</span></span></code></pre></div><h3 id="_3-2-敵方是弓兵主力-巴坦尼亞" tabindex="-1">3.2 敵方是弓兵主力（巴坦尼亞） <a class="header-anchor" href="#_3-2-敵方是弓兵主力-巴坦尼亞" aria-label="Permalink to &quot;3.2 敵方是弓兵主力（巴坦尼亞）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>對策：</span></span>
<span class="line"><span>- 騎兵直接衝他們弓兵群（弓兵近戰 = 死）</span></span>
<span class="line"><span>- 步兵舉盾推進（盾牌擋箭）</span></span>
<span class="line"><span>- 不要在高地跟他們對射（你射不贏費奧納勇士）</span></span></code></pre></div><h3 id="_3-3-敵方是步兵主力-斯特吉亞-帝國" tabindex="-1">3.3 敵方是步兵主力（斯特吉亞/帝國） <a class="header-anchor" href="#_3-3-敵方是步兵主力-斯特吉亞-帝國" aria-label="Permalink to &quot;3.3 敵方是步兵主力（斯特吉亞/帝國）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>對策：</span></span>
<span class="line"><span>- 弓兵放高處射，消耗他們</span></span>
<span class="line"><span>- 騎兵反覆衝鋒（衝完拉走，不要留在裡面）</span></span>
<span class="line"><span>- 你自己的步兵不要正面對撞（斯特吉亞斧兵近戰無敵）</span></span></code></pre></div><hr><h2 id="四、兵種配比黃金法則" tabindex="-1">四、兵種配比黃金法則 <a class="header-anchor" href="#四、兵種配比黃金法則" aria-label="Permalink to &quot;四、兵種配比黃金法則&quot;">​</a></h2><table tabindex="0"><thead><tr><th>軍隊規模</th><th style="text-align:center;">步兵</th><th style="text-align:center;">弓兵</th><th style="text-align:center;">騎兵</th></tr></thead><tbody><tr><td>小隊（50 人以下）</td><td style="text-align:center;">40%</td><td style="text-align:center;">30%</td><td style="text-align:center;">30%</td></tr><tr><td>中隊（50-100 人）</td><td style="text-align:center;">35%</td><td style="text-align:center;">35%</td><td style="text-align:center;">30%</td></tr><tr><td>大軍（100+ 人）</td><td style="text-align:center;">30%</td><td style="text-align:center;">35%</td><td style="text-align:center;">35%</td></tr></tbody></table><blockquote><p>永遠不要 100% 同一種兵。單一兵種 = 被剋到死。</p></blockquote><hr><h2 id="五、戰鬥指揮-check-list" tabindex="-1">五、戰鬥指揮 check list <a class="header-anchor" href="#五、戰鬥指揮-check-list" aria-label="Permalink to &quot;五、戰鬥指揮 check list&quot;">​</a></h2><p>每場戰鬥開始時：</p><ul><li>[ ] 弓兵找到高地了嗎？</li><li>[ ] 步兵開盾牆了嗎？</li><li>[ ] 騎兵在側翼了嗎？</li><li>[ ] 看清楚敵方兵種組成？（騎兵多？弓兵多？）</li><li>[ ] 地形對誰有利？（森林=騎兵廢，高地=弓兵強）</li></ul><hr><h2 id="📖-相關攻略" tabindex="-1">📖 相關攻略 <a class="header-anchor" href="#📖-相關攻略" aria-label="Permalink to &quot;📖 相關攻略&quot;">​</a></h2><ul><li><a href="./combat-tactics.html">騎砍2 | 戰鬥技巧完全指南</a></li><li><a href="./troop-tier-list.html">騎砍2 | 兵種大亂鬥</a></li></ul><hr><p><em>Blades Game 游刃攻略 — 遊刃有餘的遊戲攻略。全部原創內容，未經授權禁止轉載。</em></p><hr><h2 id="更新紀錄" tabindex="-1">更新紀錄 <a class="header-anchor" href="#更新紀錄" aria-label="Permalink to &quot;更新紀錄&quot;">​</a></h2><ul><li><strong>2026-06-11</strong>：文章建立。依據遊戲 v1.4.x 正式版撰寫。</li></ul>`,38)])])}const b=s(l,[["render",i]]);export{u as __pageData,b as default};
